import React, { memo } from "react";

function Footer() {
  const year = new Date().getFullYear();
  return (
    <footer className="bg-white border-t border-gray-200 py-4 px-6 mt-auto">
      <div className="max-w-7xl mx-auto flex flex-col sm:flex-row items-center justify-between gap-2 text-xs text-gray-400">
        <span>© {year} SICOPS — Sistema de Control de Obras y Porcentajes</span>
        <span className="flex items-center gap-1">
          <span className="w-1.5 h-1.5 rounded-full bg-green-400 inline-block" />
          Modo Mock — sin conexión a API
        </span>
      </div>
    </footer>
  );
}

export default memo(Footer);
